window.SmartRisk=window.SmartRisk||{};SmartRisk.Card={panel({title,badge="",body=""}){return `<article class="panel"><header class="panel-header"><h2 class="section-title">${title}</h2>${badge?`<span class="badge">${badge}</span>`:""}</header><div class="panel-body">${body}</div></article>`},metric({label,value,note,icon,trend}){return `<article class="metric-card"><div class="metric-top"><span class="metric-icon">${SmartRisk.Icon.render(icon,21)}</span><span class="trend-positive">${trend}</span></div><div class="metric-label">${label}</div><div class="metric-value">${value}</div><p class="metric-note">${note}</p></article>`}};